    payload = {
        "model": args.model,
        "messages": messages,
        "temperature": args.temperature,
        "stream": args.stream,
    }
    if args.max_tokens is not None:
        payload["max_tokens"] = args.max_tokens
    return payload


def extract_text(data):
    try:
        return data["choices"][0]["message"]["content"]
    except Exception:
        return json.dumps(data, ensure_ascii=False, indent=2)


def parse_sse(raw):
    chunks = []
    for line in raw.splitlines():
        line = line.strip()
        if not line.startswith("data:"):
            continue
        data_part = line[5:].strip()
        if not data_part or data_part == "[DONE]":
            continue
        try:
            obj = json.loads(data_part)
        except json.JSONDecodeError:
            continue
        try:
            delta = obj["choices"][0].get("delta", {})
            content = delta.get("content")
            if content:
                chunks.append(content)
        except Exception:
            continue
    return "".join(chunks)


def main():
    parser = argparse.ArgumentParser(description="Call SugarAI OpenAI-compatible chat completions endpoint")
    parser.add_argument("--prompt", required=True, help="User prompt")
    parser.add_argument("--system", default="", help="Optional system prompt")
    parser.add_argument("--model", default="grok-4.20-beta", help="Model name")
    parser.add_argument("--timeout", type=int, default=180, help="HTTP timeout seconds")
    parser.add_argument("--max-tokens", type=int, default=None, help="Optional max_tokens")
    parser.add_argument("--temperature", type=float, default=0.2, help="Sampling temperature")
    parser.add_argument("--json", action="store_true", help="Print full JSON response")
    parser.add_argument("--stream", action="store_true", default=True, help="Request streaming response")
    parser.add_argument("--no-stream", dest="stream", action="store_false", help="Request non-streaming response")
    args = parser.parse_args()

    payload = build_payload(args)
    body = json.dumps(payload, ensure_ascii=False).encode("utf-8")
    req = urllib.request.Request(
        DEFAULT_URL,
        data=body,
        headers={
            "Content-Type": "application/json",
            "Authorization": f"Bearer {DEFAULT_KEY}",
        },
        method="POST",
    )

    try:
        with urllib.request.urlopen(req, timeout=args.timeout) as resp:
            raw = resp.read().decode("utf-8", errors="replace")
    except urllib.error.HTTPError as e:
        detail = e.read().decode("utf-8", errors="replace")
        print(f"HTTPError {e.code}: {detail}", file=sys.stderr)
        sys.exit(1)
    except Exception as e:
        print(f"Request failed: {e}", file=sys.stderr)
        sys.exit(1)

    if raw.lstrip().startswith("data:"):
        text = parse_sse(raw)
        if args.json:
            print(raw)
        else:
            print(text)
        return

    try:
        data = json.loads(raw)
    except json.JSONDecodeError:
        print(raw)
        return

    if args.json:
        print(json.dumps(data, ensure_ascii=False, indent=2))
    else:
        print(extract_text(data))


if __name__ == "__main__":
    main()
